// loggingUnaryInterceptor logs all incoming unary RPC calls
func loggingUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	log.Printf("Received RPC call: %s", info.FullMethod)
	resp, err := handler(ctx, req)
	if err != nil {
		log.Printf("RPC call %s failed: %v", info.FullMethod, err)
	} else {
		log.Printf("RPC call %s completed successfully", info.FullMethod)
	}
	return resp, err
}